CREATE OR REPLACE FUNCTION public.calculate_trending_score(article_id uuid, base_score numeric DEFAULT 50.0)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    final_score DECIMAL := base_score;
    article_age_hours INTEGER;
    category_boost DECIMAL := 0.0;
    breaking_boost DECIMAL := 0.0;
    hot_boost DECIMAL := 0.0;
    recency_factor DECIMAL := 1.0;
BEGIN
    -- Get article age in hours
    SELECT EXTRACT(EPOCH FROM (NOW() - created_at)) / 3600
    INTO article_age_hours
    FROM digest_articles
    WHERE id = article_id;

    -- Apply recency factor (newer articles get higher scores)
    IF article_age_hours <= 2 THEN
        recency_factor := 2.0;
    ELSIF article_age_hours <= 6 THEN
        recency_factor := 1.5;
    ELSIF article_age_hours <= 12 THEN
        recency_factor := 1.2;
    ELSIF article_age_hours <= 24 THEN
        recency_factor := 1.0;
    ELSE
        recency_factor := 0.8;
    END IF;

    -- Apply category-specific boosts
    SELECT CASE
        WHEN category IN ('Technology', 'Business') THEN 10.0
        WHEN category IN ('Environment', 'Science') THEN 8.0
        WHEN category IN ('Health', 'Politics') THEN 6.0
        ELSE 5.0
    END INTO category_boost
    FROM digest_articles
    WHERE id = article_id;

    -- Apply breaking/hot article boosts
    SELECT
        CASE WHEN is_breaking THEN 20.0 ELSE 0.0 END,
        CASE WHEN is_hot THEN 15.0 ELSE 0.0 END
    INTO breaking_boost, hot_boost
    FROM digest_articles
    WHERE id = article_id;

    -- Calculate final score
    final_score := (base_score + category_boost + breaking_boost + hot_boost) * recency_factor;

    -- Cap the score at 100
    IF final_score > 100.0 THEN
        final_score := 100.0;
    END IF;

    RETURN final_score;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_user_level(points integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
BEGIN
    CASE
        WHEN points >= 5000 THEN RETURN 'Master';
        WHEN points >= 3000 THEN RETURN 'Expert';
        WHEN points >= 1500 THEN RETURN 'Advanced';
        WHEN points >= 500 THEN RETURN 'Intermediate';
        ELSE RETURN 'Beginner';
    END CASE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_expired_quiz_sessions()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    cleaned_count INTEGER;
BEGIN
    -- Only clean up completed sessions older than 30 days to free up space
    -- Active and paused sessions are preserved indefinitely to allow resume
    DELETE FROM quiz_sessions
    WHERE session_state = 'completed'
    AND updated_at < CURRENT_TIMESTAMP - INTERVAL '30 days';

    GET DIAGNOSTICS cleaned_count = ROW_COUNT;

    RETURN cleaned_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_friendship_on_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- If a friend request is cancelled or deleted, remove the friendship
    IF (OLD.status = 'accepted' AND NEW.status IN ('cancelled', 'rejected')) OR TG_OP = 'DELETE' THEN
        DELETE FROM friendships
        WHERE (user1_id = LEAST(OLD.requester_id, OLD.requested_id)
               AND user2_id = GREATEST(OLD.requester_id, OLD.requested_id));
    END IF;

    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_old_deleted_notifications(p_days_old integer DEFAULT 30)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    deleted_count INTEGER;
BEGIN
    DELETE FROM notifications
    WHERE is_deleted = TRUE
      AND deleted_at < (CURRENT_TIMESTAMP - INTERVAL '1 day' * p_days_old);

    GET DIAGNOSTICS deleted_count = ROW_COUNT;

    RETURN deleted_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_achievement_notification(p_user_id uuid, p_achievement_id uuid, p_achievement_key character varying, p_achievement_title character varying, p_achievement_description text, p_points_awarded integer)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    notification_id UUID;
BEGIN
    INSERT INTO notifications (
        user_id,
        type,
        title,
        message,
        related_entity_id,
        related_entity_type,
        data,
        created_at
    )
    VALUES (
        p_user_id,
        'achievement_unlocked',
        'Achievement Unlocked!',
        'You unlocked: ' || p_achievement_title,
        p_achievement_id,
        'achievement',
        jsonb_build_object(
            'achievement_id', p_achievement_id,
            'achievement_key', p_achievement_key,
            'achievement_title', p_achievement_title,
            'achievement_description', p_achievement_description,
            'points_awarded', p_points_awarded
        ),
        CURRENT_TIMESTAMP
    )
    RETURNING id INTO notification_id;

    RETURN notification_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_challenge_notification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Create notification for new challenge
    IF TG_OP = 'INSERT' THEN
        INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
        SELECT
            NEW.challengee_id,
            'challenge_received',
            'New Challenge Received',
            u.name || ' challenged you to a quiz!',
            NEW.challenger_id,
            NEW.id,
            'challenge',
            jsonb_build_object(
                'challenge_id', NEW.id,
                'challenger_name', u.name,
                'quiz_id', NEW.quiz_id,
                'message', NEW.message,
                'expires_at', NEW.expires_at
            ),
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.challenger_id;

        RETURN NEW;
    END IF;

    -- Create notification for challenge status changes
    IF TG_OP = 'UPDATE' THEN
        -- Challenge accepted
        IF NEW.status = 'accepted' AND OLD.status = 'pending' THEN
            INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_accepted',
                'Challenge Accepted',
                u.name || ' accepted your challenge!',
                NEW.challengee_id,
                NEW.id,
                'challenge',
                jsonb_build_object(
                    'challenge_id', NEW.id,
                    'accepter_name', u.name,
                    'quiz_id', NEW.quiz_id
                ),
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challengee_id;
        END IF;

        -- Challenge declined
        IF NEW.status = 'declined' AND OLD.status = 'pending' THEN
            INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_declined',
                'Challenge Declined',
                u.name || ' declined your challenge.',
                NEW.challengee_id,
                NEW.id,
                'challenge',
                jsonb_build_object(
                    'challenge_id', NEW.id,
                    'decliner_name', u.name,
                    'quiz_id', NEW.quiz_id
                ),
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challengee_id;
        END IF;

        -- Challenger completed (notify challengee)
        IF NEW.status = 'challenger_completed' AND OLD.status = 'accepted' THEN
            INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
            SELECT
                NEW.challengee_id,
                'challenge_progress',
                'Opponent Completed Quiz',
                u.name || ' completed the challenge quiz. Your turn!',
                NEW.challenger_id,
                NEW.id,
                'challenge',
                jsonb_build_object(
                    'challenge_id', NEW.id,
                    'opponent_name', u.name,
                    'quiz_id', NEW.quiz_id
                ),
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challenger_id;
        END IF;

        -- Challengee completed (notify challenger)
        IF NEW.status = 'challengee_completed' AND OLD.status = 'accepted' THEN
            INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_progress',
                'Opponent Completed Quiz',
                u.name || ' completed the challenge quiz. Your turn!',
                NEW.challengee_id,
                NEW.id,
                'challenge',
                jsonb_build_object(
                    'challenge_id', NEW.id,
                    'opponent_name', u.name,
                    'quiz_id', NEW.quiz_id
                ),
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challengee_id;
        END IF;

        -- Challenge completed (both finished) - determine winner and notify both
        IF NEW.status = 'completed' AND OLD.status IN ('challenger_completed', 'challengee_completed') THEN
            -- Create completion notification for challenger
            INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_completed',
                'Challenge Completed',
                CASE
                    WHEN NEW.challenger_score > NEW.challengee_score THEN 'You won the challenge against ' || u.name || '!'
                    WHEN NEW.challenger_score < NEW.challengee_score THEN 'You lost the challenge against ' || u.name || '.'
                    ELSE 'Your challenge with ' || u.name || ' ended in a tie!'
                END,
                NEW.challengee_id,
                NEW.id,
                'challenge',
                jsonb_build_object(
                    'challenge_id', NEW.id,
                    'opponent_name', u.name,
                    'quiz_id', NEW.quiz_id,
                    'your_score', NEW.challenger_score,
                    'opponent_score', NEW.challengee_score,
                    'result', CASE
                        WHEN NEW.challenger_score > NEW.challengee_score THEN 'won'
                        WHEN NEW.challenger_score < NEW.challengee_score THEN 'lost'
                        ELSE 'tie'
                    END
                ),
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challengee_id;

            -- Create completion notification for challengee
            INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
            SELECT
                NEW.challengee_id,
                'challenge_completed',
                'Challenge Completed',
                CASE
                    WHEN NEW.challengee_score > NEW.challenger_score THEN 'You won the challenge against ' || u.name || '!'
                    WHEN NEW.challengee_score < NEW.challenger_score THEN 'You lost the challenge against ' || u.name || '.'
                    ELSE 'Your challenge with ' || u.name || ' ended in a tie!'
                END,
                NEW.challenger_id,
                NEW.id,
                'challenge',
                jsonb_build_object(
                    'challenge_id', NEW.id,
                    'opponent_name', u.name,
                    'quiz_id', NEW.quiz_id,
                    'your_score', NEW.challengee_score,
                    'opponent_score', NEW.challenger_score,
                    'result', CASE
                        WHEN NEW.challengee_score > NEW.challenger_score THEN 'won'
                        WHEN NEW.challengee_score < NEW.challenger_score THEN 'lost'
                        ELSE 'tie'
                    END
                ),
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challenger_id;
        END IF;

        RETURN NEW;
    END IF;

    RETURN NULL;
END;
$function$
;

