CREATE OR REPLACE FUNCTION public.create_friendship_on_accept()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Only create friendship if status changed to 'accepted'
    IF NEW.status = 'accepted' AND OLD.status != 'accepted' THEN
        -- Ensure user1_id < user2_id for consistent ordering
        INSERT INTO friendships (user1_id, user2_id, created_at)
        VALUES (
            LEAST(NEW.requester_id, NEW.requested_id),
            GREATEST(NEW.requester_id, NEW.requested_id),
            CURRENT_TIMESTAMP
        )
        ON CONFLICT (user1_id, user2_id) DO NOTHING;

        -- Update responded_at timestamp
        NEW.responded_at = CURRENT_TIMESTAMP;

        -- Create notification for requester
        INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
        SELECT
            NEW.requester_id,
            'friend_accepted',
            'Friend Request Accepted',
            u.name || ' accepted your friend request!',
            NEW.requested_id,
            NEW.id,
            'friend_request',
            jsonb_build_object(
                'friend_request_id', NEW.id,
                'accepter_name', u.name
            ),
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.requested_id;
    END IF;

    -- Create notification for rejection
    IF NEW.status = 'rejected' AND OLD.status != 'rejected' THEN
        NEW.responded_at = CURRENT_TIMESTAMP;

        INSERT INTO notifications (user_id, type, title, message, related_user_id, related_entity_id, related_entity_type, data, created_at)
        SELECT
            NEW.requester_id,
            'friend_rejected',
            'Friend Request Declined',
            u.name || ' declined your friend request.',
            NEW.requested_id,
            NEW.id,
            'friend_request',
            jsonb_build_object(
                'friend_request_id', NEW.id,
                'decliner_name', u.name
            ),
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.requested_id;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_challenges()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Auto-expire challenges that are past their expiry date
    UPDATE challenges
    SET status = 'expired', updated_at = CURRENT_TIMESTAMP
    WHERE expires_at < CURRENT_TIMESTAMP
    AND status IN ('pending', 'accepted');

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_user_by_supabase_id(p_supabase_id uuid)
 RETURNS TABLE(id uuid, email character varying, name character varying, auth_method character varying, created_at timestamp without time zone, updated_at timestamp without time zone)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT
        u.id,
        u.email,
        u.name,
        u.auth_method,
        u.created_at,
        u.updated_at
    FROM users u
    WHERE u.supabase_id = p_supabase_id;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.migrate_user_to_jwt(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    UPDATE users
    SET
        auth_method = 'jwt',
        supabase_id = NULL,
        last_auth_method = 'jwt',
        migrated_at = CURRENT_TIMESTAMP
    WHERE id = p_user_id;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.migrate_user_to_supabase(p_user_id uuid, p_supabase_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    -- Check if supabase_id is already in use
    IF EXISTS (SELECT 1 FROM users WHERE supabase_id = p_supabase_id) THEN
        RAISE EXCEPTION 'Supabase ID already linked to another user';
    END IF;

    UPDATE users
    SET
        auth_method = 'supabase',
        supabase_id = p_supabase_id,
        last_auth_method = 'supabase',
        migrated_at = CURRENT_TIMESTAMP
    WHERE id = p_user_id;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.restore_notification(p_notification_id uuid, p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    UPDATE notifications
    SET is_deleted = FALSE, deleted_at = NULL
    WHERE id = p_notification_id
      AND user_id = p_user_id
      AND is_deleted = TRUE;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

