    IF OLD.last_auth_method IS DISTINCT FROM NEW.last_auth_method THEN
        NEW.last_active = CURRENT_TIMESTAMP;
        NEW.updated_at = CURRENT_TIMESTAMP;
    END IF;

    RETURN NEW;
END;
