CREATE OR REPLACE FUNCTION public.update_user_last_auth_method(p_user_id uuid, p_auth_method character varying)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    affected_rows INTEGER;
BEGIN
    -- Validate auth method
    IF p_auth_method NOT IN ('jwt', 'supabase') THEN
        RAISE EXCEPTION 'Invalid auth method: %. Must be jwt or supabase', p_auth_method;
    END IF;

    UPDATE users
    SET
        last_auth_method = p_auth_method,
        updated_at = CURRENT_TIMESTAMP
    WHERE id = p_user_id;

    GET DIAGNOSTICS affected_rows = ROW_COUNT;

    IF affected_rows > 0 THEN
        RETURN TRUE;
    ELSE
        RETURN FALSE;
    END IF;
END;
$function$
;

