CREATE INDEX idx_users_last_active ON public.users USING btree (last_active);
CREATE INDEX idx_users_last_auth_method ON public.users USING btree (last_auth_method);
CREATE INDEX idx_users_level ON public.users USING btree (level);
CREATE INDEX idx_users_migrated_at ON public.users USING btree (migrated_at);
CREATE INDEX idx_users_supabase_id ON public.users USING btree (supabase_id);
CREATE UNIQUE INDEX idx_users_supabase_id_unique ON public.users USING btree (supabase_id) WHERE (supabase_id IS NOT NULL);
CREATE INDEX idx_users_total_points ON public.users USING btree (total_points DESC);
CREATE INDEX idx_users_total_quizzes_completed ON public.users USING btree (total_quizzes_completed DESC);
-- Triggers
CREATE TRIGGER enforce_bucket_name_length_trigger BEFORE INSERT OR UPDATE OF name ON storage.buckets FOR EACH ROW EXECUTE FUNCTION storage.enforce_bucket_name_length();
CREATE TRIGGER objects_delete_delete_prefix AFTER DELETE ON storage.objects FOR EACH ROW EXECUTE FUNCTION storage.delete_prefix_hierarchy_trigger();
CREATE TRIGGER objects_insert_create_prefix BEFORE INSERT ON storage.objects FOR EACH ROW EXECUTE FUNCTION storage.objects_insert_prefix_trigger();
CREATE TRIGGER objects_update_create_prefix BEFORE UPDATE ON storage.objects FOR EACH ROW WHEN (((new.name <> old.name) OR (new.bucket_id <> old.bucket_id))) EXECUTE FUNCTION storage.objects_update_prefix_trigger();
CREATE TRIGGER prefixes_create_hierarchy BEFORE INSERT ON storage.prefixes FOR EACH ROW WHEN ((pg_trigger_depth() < 1)) EXECUTE FUNCTION storage.prefixes_insert_trigger();
CREATE TRIGGER prefixes_delete_hierarchy AFTER DELETE ON storage.prefixes FOR EACH ROW EXECUTE FUNCTION storage.delete_prefix_hierarchy_trigger();
CREATE TRIGGER tr_check_filters BEFORE INSERT OR UPDATE ON realtime.subscription FOR EACH ROW EXECUTE FUNCTION realtime.subscription_check_filters();
CREATE TRIGGER trigger_cleanup_friendship_on_status_change BEFORE DELETE OR UPDATE ON public.friend_requests FOR EACH ROW EXECUTE FUNCTION cleanup_friendship_on_status_change();
CREATE TRIGGER trigger_create_challenge_notification AFTER INSERT OR UPDATE ON public.challenges FOR EACH ROW EXECUTE FUNCTION create_challenge_notification();
CREATE TRIGGER trigger_create_friend_request_notification AFTER INSERT ON public.friend_requests FOR EACH ROW EXECUTE FUNCTION create_friend_request_notification();
CREATE TRIGGER trigger_create_friendship_on_accept BEFORE UPDATE ON public.friend_requests FOR EACH ROW EXECUTE FUNCTION create_friendship_on_accept();
CREATE TRIGGER trigger_update_challenges_updated_at BEFORE UPDATE ON public.challenges FOR EACH ROW EXECUTE FUNCTION update_challenges_updated_at();
CREATE TRIGGER trigger_update_last_active_on_auth BEFORE UPDATE OF last_auth_method ON public.users FOR EACH ROW EXECUTE FUNCTION update_last_active_on_auth();
CREATE TRIGGER trigger_update_user_preferences_updated_at BEFORE UPDATE ON public.user_preferences FOR EACH ROW EXECUTE FUNCTION update_user_preferences_updated_at();
CREATE TRIGGER update_achievements_updated_at BEFORE UPDATE ON public.achievements FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_app_settings_updated_at BEFORE UPDATE ON public.app_settings FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_difficulty_levels_updated_at BEFORE UPDATE ON public.difficulty_levels FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_discussion_replies_updated_at BEFORE UPDATE ON public.discussion_replies FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_discussions_updated_at BEFORE UPDATE ON public.discussions FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_interests_updated_at BEFORE UPDATE ON public.categories FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_notification_frequencies_updated_at BEFORE UPDATE ON public.notification_frequencies FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_objects_updated_at BEFORE UPDATE ON storage.objects FOR EACH ROW EXECUTE FUNCTION storage.update_updated_at_column();
CREATE TRIGGER update_quiz_attempts_updated_at BEFORE UPDATE ON public.quiz_attempts FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_quiz_session_activity_trigger BEFORE UPDATE ON public.quiz_sessions FOR EACH ROW EXECUTE FUNCTION update_quiz_session_activity();
CREATE TRIGGER update_quiz_sessions_updated_at BEFORE UPDATE ON public.quiz_sessions FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_quiz_statistics_last_updated BEFORE UPDATE ON public.quiz_statistics FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_quizzes_updated_at BEFORE UPDATE ON public.quizzes FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_user_category_performance_updated_at BEFORE UPDATE ON public.user_category_performance FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
CREATE TRIGGER update_users_level_on_points_change BEFORE UPDATE OF total_points ON public.users FOR EACH ROW WHEN ((old.total_points IS DISTINCT FROM new.total_points)) EXECUTE FUNCTION update_user_level();
CREATE TRIGGER update_users_updated_at BEFORE UPDATE ON public.users FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();
